 18→ALFPWorldMapManager* ULFPWorldMapEditorComponent::GetWorldMapManager() const
 19→{
 20→	if (!CachedWorldMapManager)
 21→	{
 22→		TArray<AActor*> Managers;
 23→		UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPWorldMapManager::StaticClass(), Managers);
 24→		if (Managers.Num() > 0)
 25→		{
 26→			CachedWorldMapManager = Cast<ALFPWorldMapManager>(Managers[0]);
 27→		}
 28→	}
 29→	return CachedWorldMapManager;
 30→}
