252→void ULFPWorldMapEditorComponent::RemoveSelectedNode()
253→{
254→	if (!SelectedNode) return;
255→
256→	ALFPWorldMapManager* Manager = GetWorldMapManager();
257→	if (!Manager) return;
258→
259→	int32 NodeID = SelectedNode->NodeID;
260→	Manager->RemoveNode(NodeID);
261→	SelectedNode = nullptr;
262→
263→	UE_LOG(LogTemp, Log, TEXT("删除节点 %d"), NodeID);
264→}
